import { env } from "../config.js";

const BASE_URL = "https://financialmodelingprep.com/stable";

/**
 * Generic FMP fetch helper for the new /stable/ API.
 * All endpoints use query parameters (not path params).
 */
async function fmpFetch<T>(endpoint: string, params: Record<string, string> = {}): Promise<T> {
  const searchParams = new URLSearchParams({ ...params, apikey: env.FMP_API_KEY });
  const url = `${BASE_URL}/${endpoint}?${searchParams.toString()}`;

  const response = await fetch(url, { signal: AbortSignal.timeout(10000) });

  if (!response.ok) {
    const body = await response.text().catch(() => "");
    throw new Error(`FMP API error: ${response.status} for /${endpoint} — ${body.substring(0, 200)}`);
  }

  return response.json() as Promise<T>;
}

// ---- FMP response types ----

interface FMPSearchResult {
  symbol: string;
  name: string;
  currency: string;
  stockExchange: string;
  exchangeShortName: string;
}

interface FMPProfile {
  symbol: string;
  companyName: string;
  exchange: string;
  industry: string;
  sector: string;
  ceo: string;
  fullTimeEmployees: string;
  mktCap: number;
  description: string;
  website: string;
  image: string;
  price: number;
}

interface FMPIncomeStatement {
  date: string;
  revenue: number;
  netIncome: number;
  eps: number;
}

interface FMPBalanceSheet {
  totalCurrentAssets: number;
  totalCurrentLiabilities: number;
  totalDebt: number;
  totalStockholdersEquity: number;
}

interface FMPKeyMetrics {
  peRatio: number;
  returnOnEquity: number;
  freeCashFlowPerShare: number;
  dividendYield: number;
  debtToEquity: number;
  currentRatio: number;
  netIncomePerShare: number;
  freeCashFlow?: number;
}

interface FMPRatios {
  netProfitMargin: number;
  returnOnEquity: number;
  debtEquityRatio: number;
  currentRatio: number;
  dividendYield: number;
  priceEarningsRatio: number;
}

// ---- Public API ----

/**
 * Search for a company by name or ticker.
 * Uses the new /stable/search-name endpoint.
 * Falls back to trying the input as a direct ticker via /stable/profile.
 */
export async function searchCompany(query: string): Promise<{ ticker: string; name: string; exchange: string } | null> {
  // Strategy 1: Try search-name endpoint
  try {
    const results = await fmpFetch<FMPSearchResult[]>("search-name", { query });
    if (results && results.length > 0) {
      const exactMatch = results.find(
        (r) => r.symbol.toUpperCase() === query.toUpperCase()
      );
      const best = exactMatch || results[0];
      return {
        ticker: best.symbol,
        name: best.name,
        exchange: best.exchangeShortName || best.stockExchange,
      };
    }
  } catch (error) {
    console.warn("FMP search-name failed, trying search-symbol...", (error as Error).message);
  }

  // Strategy 2: Try search-symbol (if input looks like a ticker)
  try {
    const results = await fmpFetch<FMPSearchResult[]>("search-symbol", { query });
    if (results && results.length > 0) {
      const best = results[0];
      return {
        ticker: best.symbol,
        name: best.name,
        exchange: best.exchangeShortName || best.stockExchange,
      };
    }
  } catch (error) {
    console.warn("FMP search-symbol failed, trying direct profile...", (error as Error).message);
  }

  // Strategy 3: Try direct profile lookup (treat input as ticker)
  try {
    const profiles = await fmpFetch<FMPProfile[]>("profile", { symbol: query.toUpperCase() });
    if (profiles && profiles.length > 0) {
      const p = profiles[0];
      return {
        ticker: p.symbol,
        name: p.companyName,
        exchange: p.exchange,
      };
    }
  } catch (error) {
    console.error("FMP direct profile lookup also failed:", (error as Error).message);
  }

  return null;
}

/**
 * Fetch company profile.
 */
export async function getCompanyProfile(ticker: string) {
  try {
    const profiles = await fmpFetch<FMPProfile[]>("profile", { symbol: ticker });
    if (!profiles || profiles.length === 0) return null;

    const p = profiles[0];
    return {
      name: p.companyName,
      ticker: p.symbol,
      exchange: p.exchange,
      industry: p.industry || "N/A",
      sector: p.sector || "N/A",
      ceo: p.ceo || "N/A",
      employees: parseInt(p.fullTimeEmployees) || 0,
      marketCap: p.mktCap || 0,
      description: p.description || "",
      website: p.website || "",
      logo: p.image || "",
      currentPrice: p.price || 0,
    };
  } catch (error) {
    console.error("FMP profile failed:", error);
    return null;
  }
}

/**
 * Fetch financial data — income statements, balance sheet, key metrics, ratios.
 * Returns a consolidated Financials object.
 */
export async function getFinancials(ticker: string, currentPrice: number = 0) {
  try {
    // Fetch all financial data in parallel
    const [incomeStatements, balanceSheet, keyMetrics, ratios] = await Promise.all([
      fmpFetch<FMPIncomeStatement[]>("income-statement", { symbol: ticker, limit: "4" }).catch(() => [] as FMPIncomeStatement[]),
      fmpFetch<FMPBalanceSheet[]>("balance-sheet-statement", { symbol: ticker, limit: "1" }).catch(() => [] as FMPBalanceSheet[]),
      fmpFetch<FMPKeyMetrics[]>("key-metrics", { symbol: ticker, limit: "1" }).catch(() => [] as FMPKeyMetrics[]),
      fmpFetch<FMPRatios[]>("ratios", { symbol: ticker, limit: "1" }).catch(() => [] as FMPRatios[]),
    ]);

    const latestIncome = incomeStatements[0];
    const previousIncome = incomeStatements[1];
    const bs = balanceSheet[0];
    const km = keyMetrics[0];
    const rt = ratios[0];

    // Compute revenue growth YoY
    let revenueGrowth = 0;
    if (latestIncome && previousIncome && previousIncome.revenue > 0) {
      revenueGrowth = (latestIncome.revenue - previousIncome.revenue) / previousIncome.revenue;
    }

    // Compute current ratio from balance sheet if not in key metrics
    let computedCurrentRatio = km?.currentRatio || rt?.currentRatio || 0;
    if (!computedCurrentRatio && bs && bs.totalCurrentLiabilities > 0) {
      computedCurrentRatio = bs.totalCurrentAssets / bs.totalCurrentLiabilities;
    }

    return {
      currentPrice: currentPrice,
      revenue: latestIncome?.revenue || 0,
      revenueGrowth: revenueGrowth,
      netIncome: latestIncome?.netIncome || 0,
      eps: latestIncome?.eps || km?.netIncomePerShare || 0,
      peRatio: km?.peRatio || rt?.priceEarningsRatio || 0,
      debtToEquity: km?.debtToEquity || rt?.debtEquityRatio || 0,
      currentRatio: computedCurrentRatio,
      freeCashFlow: km?.freeCashFlow || 0,
      returnOnEquity: km?.returnOnEquity || rt?.returnOnEquity || 0,
      dividendYield: km?.dividendYield || rt?.dividendYield || 0,
      profitMargin: rt?.netProfitMargin || (latestIncome && latestIncome.revenue > 0 ? latestIncome.netIncome / latestIncome.revenue : 0),
    };
  } catch (error) {
    console.error("FMP financials failed:", error);
    return null;
  }
}

import { ChatGoogleGenerativeAI } from "@langchain/google-genai";
import { env } from "../config.js";

// Model preference: try gemini-2.0-flash first, can be overridden via env
const MODEL_NAME = process.env.GEMINI_MODEL || "gemini-2.0-flash-lite";

/**
 * Shared Gemini LLM instance.
 * Using gemini-2.0-flash-lite by default for generous free tier quota.
 * Override with GEMINI_MODEL env var if needed.
 */
export const llm = new ChatGoogleGenerativeAI({
  model: MODEL_NAME,
  apiKey: env.GOOGLE_API_KEY,
  temperature: 0.3, // Low temperature for consistent, factual output
  maxOutputTokens: 4096,
});

console.log(`🤖 LLM configured: ${MODEL_NAME}`);

/**
 * Helper to invoke Gemini and parse JSON from the response.
 * Strips markdown code fences if present.
 */
export async function invokeAndParseJSON<T>(prompt: string): Promise<T> {
  const response = await llm.invoke(prompt);
  let content = typeof response.content === "string" ? response.content : "";

  // Strip markdown code fences (```json ... ```)
  content = content.replace(/```json\s*/gi, "").replace(/```\s*/gi, "").trim();

  try {
    return JSON.parse(content) as T;
  } catch (parseError) {
    console.error("Failed to parse LLM JSON response:", content.substring(0, 500));
    throw new Error(`LLM returned invalid JSON: ${(parseError as Error).message}`);
  }
}

