const envContent = fs.readFileSync("/Users/balajinayakbardawal/Learnings/AI_application_development/Stocky/server/.env", "utf8");
const envVars = Object.fromEntries(
  envContent
    .split("\n")
    .map(line => line.trim())
    .filter(line => line && !line.startsWith("#"))
    .map(line => {
      const idx = line.indexOf("=");
      return [line.slice(0, idx).trim(), line.slice(idx + 1).trim()];
    })
);

const FMP_API_KEY = envVars.FMP_API_KEY;

function scoreResult(r, query) {
  let score = 0;
  const sym = r.symbol.toUpperCase();
  const q = query.toUpperCase();

  // Exact symbol match
  if (sym === q) score += 100;

  // Symbol contains query
  if (sym.includes(q)) score += 20;

  // No dot suffix (likely primary US listing)
  if (!sym.includes(".")) score += 50;

  // USD currency
  if (r.currency === "USD") score += 30;

  // Primary exchanges
  const ex = (r.exchange || "").toUpperCase();
  if (ex.includes("NASDAQ") || ex.includes("NYSE") || ex.includes("AMEX")) {
    score += 20;
  }

  return score;
}

async function testSearchSelection(query) {
  const url = `https://financialmodelingprep.com/stable/search-name?query=${encodeURIComponent(query)}&apikey=${FMP_API_KEY}`;
  const res = await fetch(url);
  const data = await res.json();

  const scored = data.map(r => ({
    ...r,
    _score: scoreResult(r, query)
  }));

  scored.sort((a, b) => b._score - a._score);

  console.log(`\nSearch selection for "${query}":`);
  console.log("Top 5 resolved:");
  console.log(JSON.stringify(scored.slice(0, 5), null, 2));
}

async function main() {
  await testSearchSelection("Apple");
  await testSearchSelection("AAPL");
  await testSearchSelection("Reliance");
}

main().catch(console.error);

