  // Exact ticker match
  if (sym === q) score += 500;

  // Exact name match
  if (name === q) score += 400;

  // Name starts with query
  if (name.startsWith(q)) {
    score += 200;
  } else if (name.includes(q)) {
    score += 100;
  }

  // Symbol starts with query
  if (sym.startsWith(q)) {
    score += 50;
  }

  // No dot suffix (likely primary US listing)
  if (!sym.includes(".")) score += 50;

  // USD currency
  if (r.currency === "USD") score += 30;

  // Primary exchanges
  const ex = (r.exchange || "").toUpperCase();
  if (ex.includes("NASDAQ") || ex.includes("NYSE") || ex.includes("AMEX")) {
    score += 20;
  }

  return score;
}

