export async function searchCompany(query: string): Promise<{ ticker: string; name: string; exchange: string } | null> {
  const cleanQuery = query.trim();
  if (cleanQuery.length === 0) return null;

  // Strategy 1: If the query looks like a ticker (1-5 chars, alphanumeric), try direct profile check first
  const isTickerLike = /^[A-Za-z0-9.-]{1,5}$/.test(cleanQuery);
  if (isTickerLike) {
    try {
      const profiles = await fmpFetch<FMPProfile[]>("profile", { symbol: cleanQuery.toUpperCase() });
      if (profiles && profiles.length > 0) {
        const p = profiles[0];
        return {
          ticker: p.symbol,
          name: p.companyName,
          exchange: p.exchange,
        };
      }
    } catch (error) {
      // Ignore and fall back to search
    }
  }

  // Strategy 2: Call search-name and search-symbol in parallel, then score and select the best result
  try {
    const [nameResults, symbolResults] = await Promise.all([
      fmpFetch<FMPSearchResult[]>("search-name", { query: cleanQuery }).catch(() => [] as FMPSearchResult[]),
      fmpFetch<FMPSearchResult[]>("search-symbol", { query: cleanQuery }).catch(() => [] as FMPSearchResult[]),
    ]);

    // Combine results
    const combined = [...nameResults, ...symbolResults];
    if (combined.length === 0) return null;

    // Helper to score results
    const scoreResult = (r: FMPSearchResult) => {
      let score = 0;
      const sym = r.symbol.toUpperCase();
      const name = (r.name || "").toUpperCase();
      const q = cleanQuery.toUpperCase();

      // Exact ticker match
      if (sym === q) score += 500;

      // Exact name match
      if (name === q) score += 400;

      // Name starts with query
      if (name.startsWith(q)) {
        score += 200;
      } else if (name.includes(q)) {
        score += 100;
      }

      // Symbol starts with query
      if (sym.startsWith(q)) {
        score += 50;
      }

      // No dot suffix (likely primary US listing)
      if (!sym.includes(".")) score += 50;

      // USD currency
      if (r.currency === "USD") score += 30;

      // Primary exchanges
      const ex = (r.exchange || "").toUpperCase();
      if (ex.includes("NASDAQ") || ex.includes("NYSE") || ex.includes("AMEX")) {
        score += 20;
      }

      return score;
    };

    // Sort by score descending
    const sorted = combined
      .map(r => ({ ...r, _score: scoreResult(r) }))
      .sort((a, b) => b._score - a._score);

    const best = sorted[0];
    return {
      ticker: best.symbol,
      name: best.name,
      exchange: best.exchange || best.exchangeShortName || best.stockExchange || "N/A",
    };
  } catch (error) {
    console.error("FMP search failed:", error);
  }

  return null;
}

