const GOOGLE_API_KEY = envVars.GOOGLE_API_KEY;

async function testModel(modelName) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelName}:generateContent?key=${GOOGLE_API_KEY}`;
  const response = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      contents: [{ parts: [{ text: "Hello! Respond with OK." }] }]
    })
  });
  console.log(`Model ${modelName} status:`, response.status);
  const data = await response.json();
  if (response.status !== 200) {
    console.log(`  Error:`, data.error?.message || JSON.stringify(data));
  } else {
    console.log(`  Response:`, data.candidates?.[0]?.content?.parts?.[0]?.text);
  }
}

async function main() {
  await testModel("gemini-2.0-flash");
  await testModel("gemini-2.0-flash-lite");
  await testModel("gemini-1.5-flash");
  await testModel("gemini-1.5-pro");
}

