import type { InvestmentStateType } from "../state.js";
import { invokeAndParseJSON } from "../../services/llm.js";
import { INDUSTRY_AND_QUALITATIVE_SCORING_PROMPT } from "../../services/prompts.js";

interface IndustryAndQualitativeResult {
  industry: {
    outlook: string;
    competitors: string[];
    trends: string[];
    growthDrivers: string[];
    competitivePosition: string;
  };
  businessQuality: {
    score: number;
    reasoning: string;
  };
  riskProfile: {
    score: number;
    reasoning: string;
    risks: string[];
  };
}

/**
 * Node 5: Industry Analysis & Qualitative Scoring
 * 
 * Uses Gemini to:
 * 1. Analyze the competitive landscape, competitors, and trends.
 * 2. Evaluate business quality (score + reasoning).
 * 3. Evaluate risk profile (score + reasoning + list of risks).
 * 
 * This consolidates 3 Gemini calls into 1 to prevent API rate limits.
 */
export async function industryAnalysisNode(
  state: InvestmentStateType
): Promise<Partial<InvestmentStateType>> {
  console.log("🏭 Node 5: Analyzing industry and scoring qualitative metrics...");

  if (!state.companyInfo) {
    return { errors: ["Skipping industry analysis — no company info available."] };
  }

  try {
    const prompt = INDUSTRY_AND_QUALITATIVE_SCORING_PROMPT
      .replace("{sector}", state.companyInfo.sector)
      .replace("{companyName}", state.companyInfo.name)
      .replace("{industry}", state.companyInfo.industry)
      .replace("{description}", state.companyInfo.description.substring(0, 500))
      .replace("{marketCap}", state.companyInfo.marketCap.toString())
      .replace("{employees}", state.companyInfo.employees.toString())
      .replace("{revenueGrowth}", state.financials ? (state.financials.revenueGrowth * 100).toFixed(1) : "N/A")
      .replace("{peRatio}", state.financials ? state.financials.peRatio.toFixed(1) : "N/A")
      .replace("{debtToEquity}", state.financials ? state.financials.debtToEquity.toFixed(2) : "N/A")
      .replace("{newsSentiment}", state.news?.overallSentiment || "neutral")
      .replace("{newsSummary}", state.news?.summary || "No news available.");

    const result = await invokeAndParseJSON<IndustryAndQualitativeResult>(prompt);

    console.log(`   ✅ Competitors: ${result.industry.competitors.slice(0, 3).join(", ")}`);
    console.log(`   ✅ Business Quality: ${result.businessQuality.score}/20 | Risk Profile: ${result.riskProfile.score}/20`);

    return {
      industry: result.industry,
      score: {
        businessQuality: {
          score: Math.min(Math.max(Math.round(result.businessQuality.score), 0), 20),
          max: 20,
          reasoning: result.businessQuality.reasoning,
        },
        riskProfile: {
          score: Math.min(Math.max(Math.round(result.riskProfile.score), 0), 20),
          max: 20,
          reasoning: result.riskProfile.reasoning,
        },
      } as any,
      recommendation: {
        risks: result.riskProfile.risks,
      } as any,
      sources: ["Gemini (Industry Analysis, Business Quality, Risk Assessment)"],
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    console.error("   ❌ Industry analysis failed:", message);
    return { errors: [`Industry analysis failed: ${message}`] };
  }
}

