import type { InvestmentStateType } from "../state.js";
import {
  scoreFinancialHealth,
  scoreGrowthPotential,
  scoreValuation,
} from "../../utils/scoring.js";
import type { ScoreData } from "../../utils/types.js";

/**
 * Node 6: Investment Scoring
 * 
 * Hybrid approach:
 * - Financial Health, Growth, Valuation → calculated using deterministic formulas
 * - Business Quality, Risk Profile → read pre-calculated scores from Node 5
 * 
 * No LLM calls are made here, preventing rate-limiting.
 * The reasoning explanations will be generated and filled by Node 7 (Recommendation).
 */
export async function investmentScoringNode(
  state: InvestmentStateType
): Promise<Partial<InvestmentStateType>> {
  console.log("📈 Node 6: Calculating investment score...");

  if (!state.financials) {
    return { errors: ["Skipping scoring — no financial data available."] };
  }

  try {
    // ---- Step 1: Deterministic scores ----
    const financialHealth = scoreFinancialHealth(state.financials);
    const growthPotential = scoreGrowthPotential(state.financials);
    const valuation = scoreValuation(state.financials);

    // ---- Step 2: Read qualitative scores pre-calculated by Node 5 ----
    const businessQuality = state.score?.businessQuality || {
      score: 10,
      max: 20,
      reasoning: "Qualitative evaluation was unavailable.",
    };

    const riskProfile = state.score?.riskProfile || {
      score: 10,
      max: 20,
      reasoning: "Qualitative evaluation was unavailable.",
    };

    // ---- Step 3: Calculate total ----
    const total =
      financialHealth.score +
      growthPotential.score +
      businessQuality.score +
      riskProfile.score +
      valuation.score;

    const score: ScoreData = {
      financialHealth: {
        score: financialHealth.score,
        max: 30,
        reasoning: "", // Will be filled by final recommendation node
      },
      growthPotential: {
        score: growthPotential.score,
        max: 20,
        reasoning: "", // Will be filled by final recommendation node
      },
      businessQuality,
      riskProfile,
      valuation: {
        score: valuation.score,
        max: 10,
        reasoning: "", // Will be filled by final recommendation node
      },
      total,
    };

    console.log(`   ✅ Total Score: ${total}/100 (FH:${financialHealth.score} G:${growthPotential.score} BQ:${businessQuality.score} RP:${riskProfile.score} V:${valuation.score})`);

    return {
      score,
      sources: ["Deterministic Scoring (Financial Health, Growth, Valuation)"],
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    console.error("   ❌ Scoring failed:", message);
    return { errors: [`Scoring failed: ${message}`] };
  }
}

