import type { InvestmentStateType } from "../state.js";
import { invokeAndParseJSON } from "../../services/llm.js";
import { RECOMMENDATION_WITH_REASONING_PROMPT } from "../../services/prompts.js";
import { getDecisionFromScore, computeConfidence } from "../../utils/scoring.js";
import type { RecommendationData, ScoreData } from "../../utils/types.js";

interface RecommendationWithReasoningResult extends RecommendationData {
  scoreReasonings: {
    financialHealthReasoning: string;
    growthReasoning: string;
    valuationReasoning: string;
  };
}

/**
 * Node 7: Final Recommendation & Score Reasoning Completion
 * 
 * Synthesizes all research into a professional investment recommendation
 * and completes the scoring breakdown reasonings in a single Gemini call.
 * 
 * The decision is determined by the score (deterministic).
 * The LLM's job is to explain and justify that decision and provide
 * category reasonings.
 */
export async function recommendationNode(
  state: InvestmentStateType
): Promise<Partial<InvestmentStateType>> {
  console.log("🎯 Node 7: Generating final recommendation and score reasonings...");

  if (!state.score) {
    return { errors: ["Skipping recommendation — no score available."] };
  }

  try {
    // Decision comes from the score, not from the LLM
    const decision = getDecisionFromScore(state.score.total);
    const confidence = computeConfidence(
      state.score,
      !!state.financials,
      !!state.news,
      !!state.industry
    );

    const prompt = RECOMMENDATION_WITH_REASONING_PROMPT
      .replace("{companyName}", state.companyInfo?.name || state.companyName)
      .replace("{ticker}", state.ticker)
      .replace("{companyInfo}", JSON.stringify(state.companyInfo, null, 2))
      .replace("{financials}", JSON.stringify(state.financials, null, 2))
      .replace("{news}", JSON.stringify({
        overallSentiment: state.news?.overallSentiment,
        sentimentScore: state.news?.sentimentScore,
        summary: state.news?.summary,
        articleCount: state.news?.articles.length,
      }, null, 2))
      .replace("{industry}", JSON.stringify(state.industry, null, 2))
      .replace("{totalScore}", state.score.total.toString())
      .replace("{financialHealthScore}", state.score.financialHealth.score.toString())
      .replace("{growthScore}", state.score.growthPotential.score.toString())
      .replace("{businessScore}", state.score.businessQuality.score.toString())
      .replace("{riskScore}", state.score.riskProfile.score.toString())
      .replace("{valuationScore}", state.score.valuation.score.toString())
      .replaceAll("{decision}", decision)
      .replace("{confidence}", confidence.toString());

    const result = await invokeAndParseJSON<RecommendationWithReasoningResult>(prompt);

    // Prepare updated score object
    const updatedScore: ScoreData = {
      ...state.score,
      financialHealth: {
        ...state.score.financialHealth,
        reasoning: result.scoreReasonings.financialHealthReasoning,
      },
      growthPotential: {
        ...state.score.growthPotential,
        reasoning: result.scoreReasonings.growthReasoning,
      },
      valuation: {
        ...state.score.valuation,
        reasoning: result.scoreReasonings.valuationReasoning,
      },
    };

    // Override decision and confidence with our deterministic values
    const recommendation: RecommendationData = {
      decision,
      confidence,
      reasoning: result.reasoning,
      pros: result.pros,
      cons: result.cons,
      risks: [...new Set([...(state.recommendation?.risks || []), ...(result.risks || [])])], // Merge and deduplicate risks
      shortTermOutlook: result.shortTermOutlook,
      longTermOutlook: result.longTermOutlook,
    };

    console.log(`   ✅ Decision: ${decision} | Confidence: ${confidence}%`);

    return {
      score: updatedScore,
      recommendation,
      sources: ["Gemini (Investment Recommendation, Score Reasoning)"],
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    console.error("   ❌ Recommendation generation failed:", message);

    // Fallback: create a basic recommendation from the score
    const decision = getDecisionFromScore(state.score.total);

    // Fill reasonings with fallback text
    const updatedScore: ScoreData = {
      ...state.score,
      financialHealth: {
        ...state.score.financialHealth,
        reasoning: "Quantitative scoring completed. AI explanation unavailable.",
      },
      growthPotential: {
        ...state.score.growthPotential,
        reasoning: "Quantitative scoring completed. AI explanation unavailable.",
      },
      valuation: {
        ...state.score.valuation,
        reasoning: "Quantitative scoring completed. AI explanation unavailable.",
      },
    };

    return {
      score: updatedScore,
      recommendation: {
        decision,
        confidence: 30,
        reasoning: "Automated recommendation based on quantitative analysis. Detailed AI reasoning was unavailable.",
        pros: ["Score-based analysis completed successfully"],
        cons: ["Detailed AI analysis unavailable"],
        risks: [...new Set(state.recommendation?.risks || [])],
        shortTermOutlook: "Refer to the score breakdown for details.",
        longTermOutlook: "Refer to the score breakdown for details.",
      },
      errors: [`Recommendation generation failed: ${message}`],
    };
  }
}

