/**
 * Clean query for GNews to prevent syntax errors (e.g., punctuation like dots).
 * Also strips common corporate suffixes to improve search relevance.
 */
export function cleanQueryForGNews(query: string): string {
  // Remove punctuation (dots, commas, quotes, parentheses)
  let clean = query.replace(/[.,'"()\[\]{}]/g, " ");
  // Remove multiple spaces
  clean = clean.replace(/\s+/g, " ").trim();
  // Strip common corporate suffixes
  clean = clean.replace(/\b(inc|co|ltd|corp|corporation|incorporated|limited|plc|gmbh|sa|nv|ag|holding|holdings)\b/gi, "").trim();
  // Remove multiple spaces again
  clean = clean.replace(/\s+/g, " ").trim();
  return clean || query;
}

/**
 * Search for recent news about a company.
 * Returns up to 10 articles.
 */
export async function searchNews(companyName: string): Promise<GNewsArticle[]> {
  try {
    const cleaned = cleanQueryForGNews(companyName);
    console.log(`   📰 GNews: searching for "${cleaned}" (original: "${companyName}")`);

    const query = encodeURIComponent(cleaned);
    const url = `${BASE_URL}/search?q=${query}&max=10&lang=en&apikey=${env.GNEWS_API_KEY}`;

    const response = await fetch(url, { signal: AbortSignal.timeout(10000) });

    if (!response.ok) {
      throw new Error(`GNews API error: ${response.status} ${response.statusText}`);
    }

    const data = (await response.json()) as GNewsResponse;
    return data.articles || [];
  } catch (error) {
    console.error("GNews search failed:", error);
    return [];
  }
}

