import { ChatGoogleGenerativeAI } from "@langchain/google-genai";
import { env } from "../config.js";

// Model preference: try gemini-2.0-flash-lite first, can be overridden via env
const MODEL_NAME = process.env.GEMINI_MODEL || "gemini-2.0-flash-lite";

/**
 * Shared Gemini LLM instance.
 * Using gemini-2.0-flash-lite by default for generous free tier quota.
 * Override with GEMINI_MODEL env var if needed.
 */
export const llm = new ChatGoogleGenerativeAI({
  model: MODEL_NAME,
  apiKey: env.GOOGLE_API_KEY,
  temperature: 0.3, // Low temperature for consistent, factual output
  maxOutputTokens: 4096,
});

console.log(`🤖 LLM configured: ${MODEL_NAME}`);

/**
 * Fallback to OpenRouter via direct HTTP request using native fetch.
 * Uses a free model by default (e.g. google/gemini-2.0-flash-lite:free).
 */
async function callOpenRouter(prompt: string): Promise<string> {
  const modelName = process.env.OPENROUTER_MODEL || "google/gemini-2.0-flash-lite:free";
  console.log(`   🔌 OpenRouter: falling back to model "${modelName}"`);

  const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${env.OPENROUTER_API_KEY}`,
      "HTTP-Referer": "https://github.com/InsideIIM/Stocky",
      "X-Title": "Stocky Investment Research Agent",
    },
    body: JSON.stringify({
      model: modelName,
      messages: [
        {
          role: "user",
          content: prompt,
        },
      ],
      temperature: 0.3,
    }),
  });

  if (!response.ok) {
    const errorBody = await response.text();
    throw new Error(`OpenRouter API error: ${response.status} — ${errorBody}`);
  }

  const data = (await response.json()) as any;
  return data.choices?.[0]?.message?.content || "";
}

/**
 * Helper to invoke LLM and parse JSON from the response.
 * Try Google Gemini first. If it fails, fall back to OpenRouter (if API key is present).
 * Strips markdown code fences if present.
 */
export async function invokeAndParseJSON<T>(prompt: string): Promise<T> {
  let content = "";
  let usedOpenRouter = false;

  try {
    const response = await llm.invoke(prompt);
    content = typeof response.content === "string" ? response.content : "";
  } catch (geminiError) {
    const errMessage = (geminiError as Error).message;
    console.warn(`   ⚠️ Gemini failed: ${errMessage.substring(0, 150)}...`);

    if (env.OPENROUTER_API_KEY) {
      console.log(`   🔄 Falling back to OpenRouter...`);
      try {
        content = await callOpenRouter(prompt);
        usedOpenRouter = true;
      } catch (openRouterError) {
        console.error("   ❌ OpenRouter also failed:", (openRouterError as Error).message);
        throw geminiError; // Throw the original Gemini error if OpenRouter also fails
      }
    } else {
      console.warn("   ⚠️ OPENROUTER_API_KEY is not set. Cannot fall back to OpenRouter.");
      throw geminiError;
    }
  }

  // Strip markdown code fences (```json ... ```)
  content = content.replace(/```json\s*/gi, "").replace(/```\s*/gi, "").trim();

  try {
    return JSON.parse(content) as T;
  } catch (parseError) {
    console.error(`Failed to parse LLM JSON response (OpenRouter: ${usedOpenRouter}):`, content.substring(0, 500));
    throw new Error(`LLM returned invalid JSON: ${(parseError as Error).message}`);
  }
}
